import{_ as i,o as h,c as a,ag as t}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"[Yêu cầu Nghiệp vụ] Sprint 5: Thành viên & Đánh giá (Members & Reviews)","description":"","frontmatter":{},"headers":[],"relativePath":"99-tham-khao/archive/02-quan-ly-sprint/sprint-5-thanh-vien-danh-gia/01-yeu-cau-nghiep-vu.md","filePath":"99-tham-khao/archive/02-quan-ly-sprint/sprint-5-thanh-vien-danh-gia/01-yeu-cau-nghiep-vu.md"}'),e={name:"99-tham-khao/archive/02-quan-ly-sprint/sprint-5-thanh-vien-danh-gia/01-yeu-cau-nghiep-vu.md"};function s(r,n,c,u,o,l){return h(),a("div",null,[...n[0]||(n[0]=[t('<h1 id="yeu-cau-nghiep-vu-sprint-5-thanh-vien-đanh-gia-members-reviews" tabindex="-1">[Yêu cầu Nghiệp vụ] Sprint 5: Thành viên &amp; Đánh giá (Members &amp; Reviews) <a class="header-anchor" href="#yeu-cau-nghiep-vu-sprint-5-thanh-vien-đanh-gia-members-reviews" aria-label="Permalink to &quot;[Yêu cầu Nghiệp vụ] Sprint 5: Thành viên &amp; Đánh giá (Members &amp; Reviews)&quot;">​</a></h1><p>Quản lý hệ thống khách hàng thân thiết (Loyalty) và cơ chế đánh giá/phản hồi (Review system).</p><h2 id="_1-muc-tieu-objectives" tabindex="-1">1. Mục tiêu (Objectives) <a class="header-anchor" href="#_1-muc-tieu-objectives" aria-label="Permalink to &quot;1. Mục tiêu (Objectives)&quot;">​</a></h2><ul><li>Xây dựng cộng đồng khách hàng tin cậy qua hệ thống Đánh giá 5 sao.</li><li>Giữ chân người dùng qua hệ thống Tích điểm &amp; Hạng thành viên (Silver/Gold/Platinum).</li><li>Kiểm duyệt nội dung (Moderation) để tránh spam/phản cảm.</li></ul><h2 id="_2-đac-ta-chuc-nang-functional-specs" tabindex="-1">2. Đặc tả Chức năng (Functional Specs) <a class="header-anchor" href="#_2-đac-ta-chuc-nang-functional-specs" aria-label="Permalink to &quot;2. Đặc tả Chức năng (Functional Specs)&quot;">​</a></h2><h3 id="a-he-thong-thanh-vien-loyalty-system" tabindex="-1">A. Hệ thống Thành viên (Loyalty System) <a class="header-anchor" href="#a-he-thong-thanh-vien-loyalty-system" aria-label="Permalink to &quot;A. Hệ thống Thành viên (Loyalty System)&quot;">​</a></h3><ul><li><strong>Tích điểm (Points)</strong>: Tự động cộng điểm dựa trên số tiền đã thanh toán (e.g. 100k = 1 điểm).</li><li><strong>Hạng thành viên</strong>: Phân cấp dựa trên tổng chi tiêu.</li><li><strong>Quyền lợi (Benefits)</strong>: Chiết khấu tự động cho hạng Gold trở lên.</li></ul><h3 id="b-đanh-gia-phan-hoi-reviews-ratings" tabindex="-1">B. Đánh giá &amp; Phản hồi (Reviews &amp; Ratings) <a class="header-anchor" href="#b-đanh-gia-phan-hoi-reviews-ratings" aria-label="Permalink to &quot;B. Đánh giá &amp; Phản hồi (Reviews &amp; Ratings)&quot;">​</a></h3><ul><li><strong>Viết đánh giá</strong>: Chỉ khách hàng đã hoàn thành tour (<code>COMPLETED</code>) mới được đánh giá.</li><li><strong>Nội dung</strong>: Số sao (1-5), văn bản mô tả, tối đa 3 ảnh/video.</li><li><strong>Phản hồi</strong>: Chủ tour/Admin có quyền trả lời đánh giá của khách.</li></ul><h2 id="_3-quy-tac-nghiep-vu-business-rules" tabindex="-1">3. Quy tắc Nghiệp vụ (Business Rules) <a class="header-anchor" href="#_3-quy-tac-nghiep-vu-business-rules" aria-label="Permalink to &quot;3. Quy tắc Nghiệp vụ (Business Rules)&quot;">​</a></h2><ul><li><strong>Kiểm duyệt</strong>: Đánh giá chứa từ khóa nhạy cảm (cấu hình trong Admin) sẽ chuyển sang trạng thái <code>PENDING</code> chờ duyệt.</li><li><strong>Hủy tour</strong>: Hủy tour sẽ không được tích điểm và không được đánh giá.</li></ul><hr><p><em>Tài liệu nghiệp vụ bởi PO cho Sprint 5.</em></p>',13)])])}const m=i(e,[["render",s]]);export{p as __pageData,m as default};
